export const LEGENDARY_WAR_CRATE_ID = "legendary-war-crate";

// How long a war crate stays claimable after the war ends.
const WAR_CRATE_EXPIRY_MS = 7 * 24 * 60 * 60 * 1000; // 7 days

/**
 * Check both clan war history and the village war cache for unclaimed war crates.
 * Returns an updated character with any newly-found crates added, plus a count.
 * Safe to call repeatedly — already-claimed IDs are tracked in claimedWarCrateIds.
 */
function claimPendingWarCrates(
    character: Character,
    clanData: { warHistory?: { result: string; warCrateId?: string; endedAt?: number }[] } | null,
): { character: Character; count: number } {
    const claimed = new Set(character.claimedWarCrateIds ?? []);
    const toAdd: string[] = [];
    const now = Date.now();

    // Clan war crates — check the last 3 history entries in case of back-to-back wars
    for (const record of (clanData?.warHistory ?? []).slice(0, 3)) {
        if (!record.warCrateId || record.result !== "Won") continue;
        if (claimed.has(record.warCrateId)) continue;
        if (record.endedAt && now - record.endedAt > WAR_CRATE_EXPIRY_MS) continue;
        toAdd.push(record.warCrateId);
    }

    // Village war crates — scan the shared in-memory cache
    for (const war of Object.values(sharedVillageWarCache)) {
        if (!war.warCrateId) continue;
        if (war.winnerVillage !== character.village) continue;
        if (claimed.has(war.warCrateId)) continue;
        if (!war.endedAt || now - war.endedAt > WAR_CRATE_EXPIRY_MS) continue;
        toAdd.push(war.warCrateId);
    }

    if (toAdd.length === 0) return { character, count: 0 };

    return {
        character: {
            ...character,
            inventory: [...character.inventory, ...toAdd.map(() => LEGENDARY_WAR_CRATE_ID)],
            claimedWarCrateIds: [...(character.claimedWarCrateIds ?? []), ...toAdd],
        },
        count: toAdd.length,
    };
}

type WeeklyBossStatus = "dormant" | "active" | "defeated" | "escaped";
type WeeklyBossSchedule = {
    weekKey: string;
    bossId: string;
    bossName: string;
    bossIcon: string;
    startsAt: number;
    endsAt: number;
    status: WeeklyBossStatus;
};

const weeklyBossPool = [
    { id: "ashen-dragon", name: "Ashen Dragon", icon: "DR" },
    { id: "moonshadow-oni", name: "Moonshadow Oni", icon: "ON" },
    { id: "frostfang-warlord", name: "Frostfang Warlord", icon: "FW" },
    { id: "stormveil-beast", name: "Stormveil Beast", icon: "SB" },
    { id: "deathsgate-revenant", name: "Deathsgate Revenant", icon: "DG" },
];

function seededHash(input: string) {
    let hash = 2166136261;
    for (let i = 0; i < input.length; i += 1) {
        hash ^= input.charCodeAt(i);
        hash = Math.imul(hash, 16777619);
    }
    return hash >>> 0;
}

function weekKeyForDate(date = new Date()) {
    const utc = Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate());
    const day = date.getUTCDay() || 7;
    const thursday = new Date(utc + (4 - day) * 24 * 60 * 60 * 1000);
    const yearStart = Date.UTC(thursday.getUTCFullYear(), 0, 1);
    const week = Math.ceil((((thursday.getTime() - yearStart) / 86400000) + 1) / 7);
    return `${thursday.getUTCFullYear()}-W${String(week).padStart(2, "0")}`;
}

function weeklyBossSchedule(character?: Character, now = Date.now(), overrideAi?: CreatorAi | null): WeeklyBossSchedule {
    const current = new Date(now);
    const weekKey = weekKeyForDate(current);
    const seed = seededHash(weekKey);
    const poolBoss = weeklyBossPool[seed % weeklyBossPool.length];
    const boss = overrideAi
        ? { id: overrideAi.id, name: overrideAi.name, icon: overrideAi.icon }
        : poolBoss;
    const dayOffset = (seed >>> 4) % 7;
    const hour = (seed >>> 9) % 24;
    const start = new Date(Date.UTC(current.getUTCFullYear(), current.getUTCMonth(), current.getUTCDate()));
    const startDay = start.getUTCDay() || 7;
    start.setUTCDate(start.getUTCDate() - (startDay - 1) + dayOffset);
    start.setUTCHours(hour, 0, 0, 0);
    const startsAt = start.getTime();
    const endsAt = startsAt + 24 * 60 * 60 * 1000;
    const killed = Boolean(character?.weeklyBossKills?.[weekKey]);
    const status: WeeklyBossStatus = killed ? "defeated" : now < startsAt ? "dormant" : now <= endsAt ? "active" : "escaped";
    return { weekKey, bossId: boss.id, bossName: boss.name, bossIcon: boss.icon, startsAt, endsAt, status };
}

function addInventoryItems(character: Character, itemIds: string[]) {
    return { ...character, inventory: [...character.inventory, ...itemIds] };
}

function removeInventoryItems(inventory: string[], requirements: Record<string, number>) {
    const remaining = { ...requirements };
    return inventory.filter((itemId) => {
        if (!remaining[itemId]) return true;
        remaining[itemId] -= 1;
        return false;
    });
}

function hasInventoryRequirements(character: Character, requirements: Record<string, number>) {
    return Object.entries(requirements).every(([itemId, qty]) => character.inventory.filter((id) => id === itemId).length >= qty);
}

function inventoryItemStacks(character: Character, allItems: GameItem[]) {
    const counts = new Map<string, number>();
    character.inventory.forEach((itemId) => counts.set(itemId, (counts.get(itemId) ?? 0) + 1));
    return [...counts.entries()]
        .map(([itemId, count]) => ({ itemId, count, name: itemDisplayName(itemId, allItems) }))
        .sort((a, b) => a.name.localeCompare(b.name));
}

type PlayerTransferCurrencyKey = "ryo" | "honorSeals" | "fateShards" | "boneCharms" | "auraStones" | "mythicSeals";

async function patchPlayerSaveCharacter(playerName: string, mutate: (character: Character) => Character): Promise<boolean> {
    try {
        const key = encodeURIComponent(playerName.trim().toLowerCase());
        const res = await fetch(`/api/save/${key}`, { cache: "no-store" });
        if (!res.ok) return false;
        const snap = await res.json() as Record<string, unknown> & { character?: Character };
        if (!snap.character) return false;
        const recipient = normalizeCharacter(snap.character);
        const next = { ...snap, character: mutate(recipient) };
        const saveRes = await fetch(`/api/save/${key}`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(next, (_k, value) => typeof value === "string" && value.startsWith("data:image") ? "" : value),
        });
        return saveRes.ok;
    } catch {
        return false;
    }
}

async function grantInventoryItemToPlayer(playerName: string, itemId: string, currentCharacter: Character, updateCharacter: (character: Character) => void) {
    if (playerName === currentCharacter.name) {
        updateCharacter({ ...currentCharacter, inventory: [...currentCharacter.inventory, itemId] });
        return true;
    }

    return patchPlayerSaveCharacter(playerName, recipient => ({
        ...recipient,
        inventory: [...recipient.inventory, itemId],
    }));
}

async function grantCurrencyToPlayer(playerName: string, currency: PlayerTransferCurrencyKey, amount: number, currentCharacter: Character, updateCharacter: (character: Character) => void) {
    const value = Math.max(1, Math.floor(amount));
    if (playerName === currentCharacter.name) {
        updateCharacter({ ...currentCharacter, [currency]: (currentCharacter[currency] ?? 0) + value } as Character);
        return true;
    }

    return patchPlayerSaveCharacter(playerName, recipient => ({
        ...recipient,
        [currency]: (recipient[currency] ?? 0) + value,
    } as Character));
}

