function makeJutsu(id: string, name: string, type: JutsuType, ap: number, range: number, effectPower: number, cooldown: number, chakraCost: number, staminaCost: number, tags: JutsuTag[], element: JutsuElement = "Fire"): Jutsu {
    return normalizeJutsu({ id, name, type, element, ap, range, effectPower, cooldown, currentCooldown: 0, chakraCost, staminaCost, tags });
}

function makeId() {
    return crypto.randomUUID ? crypto.randomUUID() : `${Date.now()}-${Math.random()}`;
}

export function compressDataUrl(dataUrl: string, maxPx = 512, quality = 0.82): Promise<string> {
    return new Promise((resolve) => {
        const img = new Image();
        img.onload = () => {
            const scale = Math.min(1, maxPx / Math.max(img.width, img.height));
            const canvas = document.createElement("canvas");
            canvas.width = Math.round(img.width * scale);
            canvas.height = Math.round(img.height * scale);
            canvas.getContext("2d")!.drawImage(img, 0, 0, canvas.width, canvas.height);
            // Prefer WebP (~30% smaller than JPEG at same quality); fall back to JPEG
            const webp = canvas.toDataURL("image/webp", quality);
            resolve(webp.startsWith("data:image/webp") ? webp : canvas.toDataURL("image/jpeg", quality));
        };
        img.onerror = () => resolve(dataUrl);
        img.src = dataUrl;
    });
}

// Module-level — callable from any component without prop drilling
// Mirror of api/images.ts KNOWN_PREFIXES so the client can figure out which
// category an image lives in without a round-trip. Used for sessionStorage
// cache invalidation on publish.
const CLIENT_KNOWN_PREFIXES: Record<string, string> = {
    avatar: 'avatar', pet: 'pet', jutsu: 'jutsu', item: 'item',
    card: 'card', event: 'event', bloodline: 'bloodline',
    vn: 'event', ai: 'ai', shrine: 'shrine', landmark: 'landmark',
};
function categoryFromImageKey(id: string): string {
    const prefix = id.split(':')[0];
    return CLIENT_KNOWN_PREFIXES[prefix] ?? 'misc';
}

async function publishSharedImage(id: string, img: string): Promise<boolean> {
    if (!id) return false;
    try {
        const res = await fetch('/api/images', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ id, image: img }),
        });
        if (!res.ok) throw new Error(`Image publish failed: ${res.status}`);
        // Bust the per-category sessionStorage cache so a page reload fetches
        // fresh from KV instead of hydrating the pre-publish snapshot. Without
        // this, the 10-minute IMG_CACHE_TTL would mask new assignments for
        // up to 10 minutes after a publish.
        try {
            const cat = categoryFromImageKey(id);
            sessionStorage.removeItem(`imgcat:${cat}`);
        } catch { /* sessionStorage unavailable — ignore */ }
        return true;
    } catch (error) {
        console.warn(`Could not save shared image ${id}:`, error);
        return false;
    }
}

function readImageFile(file: File, onLoad: (image: string) => void, maxSizeMb = 100) {
    if (!file.type.startsWith("image/")) return alert("Please upload an image file.");
    if (file.size > maxSizeMb * 1024 * 1024) return alert(`Please upload an image under ${maxSizeMb} MB.`);
    const reader = new FileReader();
    reader.onload = () => {
        compressDataUrl(String(reader.result)).then(onLoad);
    };
    reader.readAsDataURL(file);
}

function capStat(value: number) {
    return Math.min(MAX_STAT, Math.max(0, Math.floor(value)));
}

function xpNeeded(level: number) {
    if (level >= MAX_LEVEL) return 0;
    return level * 100;
}

const TOTAL_XP_TO_MAX_LEVEL = ((MAX_LEVEL - 1) * MAX_LEVEL / 2) * 100;

function totalXpBeforeLevel(level: number) {
    const clampedLevel = Math.max(1, Math.min(MAX_LEVEL, Math.floor(level)));
    return ((clampedLevel - 1) * clampedLevel / 2) * 100;
}

function totalXpForProgress(level: number, xp: number) {
    if (level >= MAX_LEVEL) return TOTAL_XP_TO_MAX_LEVEL;
    const currentLevelXp = Math.max(0, Math.min(xpNeeded(level), Math.floor(xp)));
    return Math.min(TOTAL_XP_TO_MAX_LEVEL, totalXpBeforeLevel(level) + currentLevelXp);
}

function maxHpForLevel(level: number) {
    return Math.min(HP_CAP, 100 + (Math.max(1, level) - 1) * 100);
}

// Endless Tower scaling — wave 1 is baseline; each wave adds a small multiplier,
// with milestone jumps every 5 and 10 waves.
export function endlessScaleFactor(wave: number): number {
    const w = Math.max(1, wave);
    const base = 1 + (w - 1) * 0.08;
    const fives = Math.floor(w / 5) * 0.10;
    const tens = Math.floor(w / 10) * 0.15;
    return Math.max(1, base + fives + tens);
}

export function endlessWaveReward(wave: number, playerLevel: number): { ryo: number; xp: number; isMilestone: boolean } {
    const factor = endlessScaleFactor(wave);
    const baseRyo = 40 + playerLevel * 6;
    const baseXp = 15 + playerLevel * 2;
    const isMilestone = wave % 5 === 0;
    const milestoneBonus = isMilestone ? (wave % 10 === 0 ? 3 : 2) : 1;
    return {
        ryo: Math.floor(baseRyo * factor * milestoneBonus),
        xp: Math.floor(baseXp * factor * milestoneBonus),
        isMilestone,
    };
}

function maxChakraForLevel(level: number) {
    return Math.min(CHAKRA_CAP, Math.floor(100 + (Math.max(1, level) - 1) * ((CHAKRA_CAP - 100) / (MAX_LEVEL - 1))));
}

function maxStaminaForLevel(level: number) {
    return Math.min(STAMINA_CAP, Math.floor(100 + (Math.max(1, level) - 1) * ((STAMINA_CAP - 100) / (MAX_LEVEL - 1))));
}

function rankFromLevel(level: number) {
    if (level >= 80) return "Special Jonin";
    if (level >= 50) return "Jonin";
    if (level >= 30) return "Chunin";
    if (level >= 15) return "Genin";
    return "Academy Student";
}

const levelOnlyRankTitles = new Set([
    "Academy Student",
    "Genin",
    "Chunin",
    "Jonin",
    "Elite Jonin",
    "Special Jonin",
    "Kage",
    "Legendary Kage",
]);

function currentMonthKey() {
    return new Date().toISOString().slice(0, 7);
}

function currentDateKey() {
    return new Date().toISOString().slice(0, 10);
}

const DAILY_MISSION_LIMIT = 20;

function dailyMissionsCompleted(character: Character) {
    return character.lastDailyReset === currentDateKey() ? character.dailyMissionsCompleted ?? 0 : 0;
}

function hasDailyMissionSlot(character: Character) {
    return dailyMissionsCompleted(character) < DAILY_MISSION_LIMIT;
}

function markMissionCompleted(character: Character): Character {
    return {
        ...character,
        clanMissionContrib: (character.clanMissionContrib ?? 0) + 1,
        totalMissionsCompleted: (character.totalMissionsCompleted ?? 0) + 1,
        dailyMissionsCompleted: dailyMissionsCompleted(character) + 1,
        lastDailyReset: currentDateKey(),
        clanContribMonth: currentMonthKey(),
    };
}

function roleRankTitle(character: Character) {
    const currentTitle = character.rankTitle?.trim();
    const lowerTitle = currentTitle?.toLowerCase() ?? "";
    const isRoleTitle = lowerTitle.includes("kage") ||
        lowerTitle.includes("elder") ||
        lowerTitle.includes("anbu") ||
        lowerTitle.includes("clan leader") ||
        lowerTitle.includes("clan head");

    if (currentTitle && isRoleTitle && !levelOnlyRankTitles.has(currentTitle)) return currentTitle;
    if (character.clanFounder) return "Clan Leader";
    return "";
}

function rankTitleForLevel(character: Character, level: number) {
    if (level < MAX_LEVEL) return rankFromLevel(level);
    return roleRankTitle(character) || "Special Jonin";
}

function baseStats(): Stats {
    return {
        strength: 10,
        speed: 10,
        intelligence: 10,
        willpower: 10,
        bukijutsuOffense: 10,
        bukijutsuDefense: 10,
        taijutsuOffense: 10,
        taijutsuDefense: 10,
        genjutsuOffense: 10,
        genjutsuDefense: 10,
        ninjutsuOffense: 10,
        ninjutsuDefense: 10,
    };
}

const TOTAL_STAT_POINTS_TO_CAP = STAT_KEYS.reduce((total, key) => total + (MAX_STAT - baseStats()[key]), 0);
const STAT_POINTS_FROM_XP_TO_CAP = TOTAL_STAT_POINTS_TO_CAP - STARTING_STAT_POINTS;

function statPointBudgetForProgress(level: number, xp: number) {
    const progressXp = totalXpForProgress(level, xp);
    const earnedFromXp = Math.floor((progressXp / TOTAL_XP_TO_MAX_LEVEL) * STAT_POINTS_FROM_XP_TO_CAP);
    return Math.min(TOTAL_STAT_POINTS_TO_CAP, STARTING_STAT_POINTS + earnedFromXp);
}

function effectiveCharacterXpGain(character: Pick<Character, "elderFocus">, amount: number) {
    const baseAmount = Math.max(0, Math.floor(amount));
    const testingBoostedAmount = Math.floor(baseAmount * CHARACTER_XP_GAIN_MULTIPLIER);
    const trainingFocusBonus = character.elderFocus === "training" ? Math.floor(testingBoostedAmount * 0.1) : 0;
    return testingBoostedAmount + trainingFocusBonus;
}

function displayCharacterXpGain(amount: number, character?: Pick<Character, "elderFocus">) {
    return character ? effectiveCharacterXpGain(character, amount) : Math.floor(Math.max(0, amount) * CHARACTER_XP_GAIN_MULTIPLIER);
}

function progressAfterXp(level: number, xp: number, amount: number) {
    let nextLevel = Math.max(1, Math.min(MAX_LEVEL, Math.floor(level)));
    let nextXp = nextLevel >= MAX_LEVEL ? 0 : Math.max(0, Math.floor(xp)) + Math.max(0, Math.floor(amount));
    while (nextLevel < MAX_LEVEL && nextXp >= xpNeeded(nextLevel)) {
        nextXp -= xpNeeded(nextLevel);
        nextLevel += 1;
    }
    if (nextLevel >= MAX_LEVEL) return { level: MAX_LEVEL, xp: 0 };
    return { level: nextLevel, xp: nextXp };
}

function statPointsEarnedFromXp(character: Character, amount: number) {
    const before = statPointBudgetForProgress(character.level, character.xp);
    const after = progressAfterXp(character.level, character.xp, effectiveCharacterXpGain(character, amount));
    return Math.max(0, statPointBudgetForProgress(after.level, after.xp) - before);
}

function normalizeStats(stats?: Partial<Stats>): Stats {
    const base = baseStats();
    return STAT_KEYS.reduce((normalized, key) => {
        normalized[key] = capStat(stats?.[key] ?? base[key]);
        return normalized;
    }, { ...base });
}

function allocatedStatPoints(stats: Stats) {
    const base = baseStats();
    return STAT_KEYS.reduce((total, key) => total + Math.max(0, capStat(stats[key]) - base[key]), 0);
}

function formatStatName(name: string) {
    return name
        .replace(/([A-Z])/g, " $1")
        .replace(/^./, (c) => c.toUpperCase());
}

function reconcileCharacterStatBudget(character: Character): Character {
    const stats = normalizeStats(character.stats);
    const earnedBudget = statPointBudgetForProgress(character.level, character.xp);
    const available = Math.max(0, earnedBudget - allocatedStatPoints(stats));
    return { ...character, stats, unspentStats: available };
}

function enemyStats(): Stats {
    return {
        strength: 25,
        speed: 25,
        intelligence: 25,
        willpower: 25,
        bukijutsuOffense: 25,
        bukijutsuDefense: 25,
        taijutsuOffense: 25,
        taijutsuDefense: 25,
        genjutsuOffense: 25,
        genjutsuDefense: 25,
        ninjutsuOffense: 25,
        ninjutsuDefense: 25,
    };
}

function scaleStat(value: number) {
    return capStat(Math.floor(value));
}

function aiPrimaryJutsuType(jutsus: Jutsu[] = []): JutsuType | undefined {
    const counts = jutsus.reduce<Record<JutsuType, number>>((acc, jutsu) => {
        acc[jutsu.type] = (acc[jutsu.type] ?? 0) + 1;
        return acc;
    }, { Any: 0, Ninjutsu: 0, Taijutsu: 0, Genjutsu: 0, Bukijutsu: 0 });
    const sorted = (Object.entries(counts) as [JutsuType, number][])
        .filter(([type]) => type !== "Any")
        .sort((a, b) => b[1] - a[1]);
    return sorted[0]?.[1] ? sorted[0][0] : undefined;
}

function aiStatsForLevel(level: number, jutsus: Jutsu[] = []): Stats {
    const safeLevel = Math.max(1, Math.min(MAX_LEVEL, Math.floor(level || 1)));
    const base = 30 + safeLevel * 16;
    const defenseLift = safeLevel * 5;
    const primaryLift = safeLevel * 9;
    const stats: Stats = {
        strength: scaleStat(base + safeLevel * 3),
        speed: scaleStat(base + safeLevel * 3),
        intelligence: scaleStat(base + safeLevel * 3),
        willpower: scaleStat(base + safeLevel * 3),
        bukijutsuOffense: scaleStat(base),
        bukijutsuDefense: scaleStat(base + defenseLift),
        taijutsuOffense: scaleStat(base),
        taijutsuDefense: scaleStat(base + defenseLift),
        genjutsuOffense: scaleStat(base),
        genjutsuDefense: scaleStat(base + defenseLift),
        ninjutsuOffense: scaleStat(base),
        ninjutsuDefense: scaleStat(base + defenseLift),
    };
    const primary = aiPrimaryJutsuType(jutsus);
    if (primary === "Bukijutsu") {
        stats.bukijutsuOffense = scaleStat(stats.bukijutsuOffense + primaryLift);
        stats.bukijutsuDefense = scaleStat(stats.bukijutsuDefense + safeLevel * 3);
        stats.strength = scaleStat(stats.strength + safeLevel * 4);
        stats.speed = scaleStat(stats.speed + safeLevel * 3);
    } else if (primary === "Taijutsu") {
        stats.taijutsuOffense = scaleStat(stats.taijutsuOffense + primaryLift);
        stats.taijutsuDefense = scaleStat(stats.taijutsuDefense + safeLevel * 3);
        stats.strength = scaleStat(stats.strength + safeLevel * 4);
        stats.speed = scaleStat(stats.speed + safeLevel * 4);
    } else if (primary === "Genjutsu") {
        stats.genjutsuOffense = scaleStat(stats.genjutsuOffense + primaryLift);
        stats.genjutsuDefense = scaleStat(stats.genjutsuDefense + safeLevel * 3);
        stats.intelligence = scaleStat(stats.intelligence + safeLevel * 4);
        stats.willpower = scaleStat(stats.willpower + safeLevel * 4);
    } else if (primary === "Ninjutsu") {
        stats.ninjutsuOffense = scaleStat(stats.ninjutsuOffense + primaryLift);
        stats.ninjutsuDefense = scaleStat(stats.ninjutsuDefense + safeLevel * 3);
        stats.intelligence = scaleStat(stats.intelligence + safeLevel * 4);
        stats.willpower = scaleStat(stats.willpower + safeLevel * 3);
    }
    return stats;
}

function aiHpForLevel(level: number, toughness = 0) {
    const safeLevel = Math.max(1, Math.min(MAX_LEVEL, Math.floor(level || 1)));
    const levelScale = safeLevel / MAX_LEVEL;
    return Math.floor(maxHpForLevel(safeLevel) * (1.12 + levelScale * 0.35 + toughness * 1.5));
}

function aiRawDamageReductionForLevel(level: number, toughness = 0) {
    const safeLevel = Math.max(1, Math.min(MAX_LEVEL, Math.floor(level || 1)));
    return clampNumber(0.06 + safeLevel * 0.005 + toughness * 0.28, 0.08, 0.62);
}

function aiArmorFactorFromRaw(rawDR: number) {
    return clampNumber(1 - rawDR, 0.45, 0.97);
}

function aiArmorFactorForLevel(level: number, toughness = 0) {
    return aiArmorFactorFromRaw(aiRawDamageReductionForLevel(level, toughness));
}

function aiArmorFactorForProfile(ai?: Pick<CreatorAi, "level" | "armorRawDR" | "armorFactor"> | null) {
    if (!ai) return 1.0;
    if (typeof ai.armorFactor === "number") return clampNumber(ai.armorFactor, 0.45, 1.0);
    if (typeof ai.armorRawDR === "number") return aiArmorFactorFromRaw(ai.armorRawDR);
    return aiArmorFactorForLevel(ai.level);
}

function addToAllStats(stats: Stats, amount: number): Stats {
    return {
        strength: capStat(stats.strength + amount),
        speed: capStat(stats.speed + amount),
        intelligence: capStat(stats.intelligence + amount),
        willpower: capStat(stats.willpower + amount),
        bukijutsuOffense: capStat(stats.bukijutsuOffense + amount),
        bukijutsuDefense: capStat(stats.bukijutsuDefense + amount),
        taijutsuOffense: capStat(stats.taijutsuOffense + amount),
        taijutsuDefense: capStat(stats.taijutsuDefense + amount),
        genjutsuOffense: capStat(stats.genjutsuOffense + amount),
        genjutsuDefense: capStat(stats.genjutsuDefense + amount),
        ninjutsuOffense: capStat(stats.ninjutsuOffense + amount),
        ninjutsuDefense: capStat(stats.ninjutsuDefense + amount),
    };
}

function maxedStats(): Stats {
    return addToAllStats(baseStats(), MAX_STAT);
}

function isAdminAccountName(name?: string): name is AdminAccount {
    return name === "Admin 1" || name === "Admin 2";
}

function normalizeAdminCharacter(character: Character): Character {
    const normalized = normalizeCharacter(character);
    if (!isAdminAccountName(normalized.name)) return normalized;
    return {
        ...normalized,
        stats: maxedStats(),
        unspentStats: 0,
    };
}

// Exam gates: players cannot level past these thresholds without passing the corresponding exam.
const EXAM_LEVEL_GATES: { exam: string; level: number; label: string }[] = [
    { exam: "genin", level: 20, label: "Genin Exam" },
    { exam: "chunin", level: 39, label: "Chunin Exam" },
    // Jonin and Special Jonin exams do not block XP — players can reach level 100 freely.
];

function examLevelCap(character: Character): number {
    const passed = character.examsPassed ?? [];
    for (const gate of EXAM_LEVEL_GATES) {
        if (!passed.includes(gate.exam)) return gate.level;
    }
    return MAX_LEVEL;
}

function gainXp(character: Character, amount: number): Character {
    const totalAmount = effectiveCharacterXpGain(character, amount);
    const levelCap = examLevelCap(character);
    let updated: Character = reconcileCharacterStatBudget(character);
    updated = { ...updated, xp: updated.level >= MAX_LEVEL ? 0 : updated.xp + totalAmount };
    while (updated.level < MAX_LEVEL && updated.level < levelCap && updated.xp >= xpNeeded(updated.level)) {
        const needed = xpNeeded(updated.level);
        const newLevel = updated.level + 1;
        const nextMaxHp = maxHpForLevel(newLevel);
        const nextMaxChakra = maxChakraForLevel(newLevel);
        const nextMaxStamina = maxStaminaForLevel(newLevel);
        updated = {
            ...updated,
            xp: updated.xp - needed,
            level: newLevel,
            rankTitle: rankTitleForLevel(updated, newLevel),
            maxHp: nextMaxHp,
            maxChakra: nextMaxChakra,
            maxStamina: nextMaxStamina,
            hp: nextMaxHp,
            chakra: nextMaxChakra,
            stamina: nextMaxStamina,
        };
    }
    // If capped by exam gate, clamp XP so it doesn't overflow past the level threshold
    if (updated.level >= levelCap && updated.level < MAX_LEVEL) {
        updated = { ...updated, xp: Math.min(updated.xp, xpNeeded(updated.level) - 1) };
    }
    if (updated.level >= MAX_LEVEL) {
        updated = { ...updated, level: MAX_LEVEL, xp: 0, rankTitle: rankTitleForLevel(updated, MAX_LEVEL) };
    }
    return reconcileCharacterStatBudget(updated);
}

const rewardCurrencyOptions: Array<{ key: RewardCurrencyKey; label: string }> = [
    { key: "fateShards", label: "Fate Shards" },
    { key: "honorSeals", label: "Honor Seals" },
    { key: "boneCharms", label: "Bone Charms" },
    { key: "auraStones", label: "Aura Stones" },
    { key: "auraDust", label: "Aura Dust" },
    { key: "mythicSeals", label: "Mythic Seals" },
];

function normalizeCurrencyRewards(rewards?: CurrencyRewards): CurrencyRewards {
    const normalized: CurrencyRewards = {};
    rewardCurrencyOptions.forEach(({ key }) => {
        const value = Math.max(0, Math.floor(Number(rewards?.[key] ?? 0)));
        if (value > 0) normalized[key] = value;
    });
    return normalized;
}

function singleCurrencyReward(key: RewardCurrencyKey, amount: number): CurrencyRewards | undefined {
    const value = Math.max(0, Math.floor(Number(amount)));
    return value > 0 ? ({ [key]: value } as CurrencyRewards) : undefined;
}

function firstCurrencyReward(rewards?: CurrencyRewards): { key: RewardCurrencyKey; amount: number } {
    const normalized = normalizeCurrencyRewards(rewards);
    const found = rewardCurrencyOptions.find(({ key }) => (normalized[key] ?? 0) > 0);
    return { key: found?.key ?? "fateShards", amount: found ? normalized[found.key] ?? 0 : 0 };
}

function applyCurrencyRewards(character: Character, rewards?: CurrencyRewards): Character {
    const normalized = normalizeCurrencyRewards(rewards);
    return rewardCurrencyOptions.reduce<Character>((updated, { key }) => {
        const amount = normalized[key] ?? 0;
        return amount > 0 ? { ...updated, [key]: (updated[key] ?? 0) + amount } : updated;
    }, character);
}

function formatCurrencyRewards(rewards?: CurrencyRewards): string {
    const normalized = normalizeCurrencyRewards(rewards);
    return rewardCurrencyOptions
        .filter(({ key }) => (normalized[key] ?? 0) > 0)
        .map(({ key, label }) => `+${normalized[key]} ${label}`)
        .join(" / ");
}

function rewardSummary(xp: number, ryo: number, stamina: number, rewards?: CurrencyRewards, character?: Pick<Character, "elderFocus">): string {
    return [`+${displayCharacterXpGain(xp, character)} XP`, `+${ryo} ryo`, `+${stamina} stamina`, formatCurrencyRewards(rewards)].filter(Boolean).join(" / ");
}

