function defaultVillageUpgrades(): VillageUpgrades {
    return {
        training: 0,
        jutsuTraining: 0,
        shop: 0,
        townDefense: 0,
        petYard: 0,
        bank: 0,
        missionHall: 0,
        hospital: 0,
    };
}

function normalizeVillageUpgrades(upgrades?: Partial<VillageUpgrades>): VillageUpgrades {
    const defaults = defaultVillageUpgrades();
    const normalized = { ...defaults, ...(upgrades ?? {}) } as VillageUpgrades;
    for (const key of Object.keys(defaults) as VillageUpgradeKey[]) {
        normalized[key] = clampNumber(Math.floor(Number(normalized[key] ?? 0)), 0, VILLAGE_UPGRADE_MAX_LEVEL);
    }
    return normalized;
}

function getVillageUpgrades(character: Character): VillageUpgrades {
    return normalizeVillageUpgrades(character.villageUpgrades);
}

function villageUpgradeLevel(character: Character, key: VillageUpgradeKey): number {
    return getVillageUpgrades(character)[key] ?? 0;
}

function villageUpgradeBonus(character: Character, key: VillageUpgradeKey): number {
    const def = villageUpgradeDefinitions.find((upgrade) => upgrade.key === key);
    return villageUpgradeLevel(character, key) * (def?.perLevel ?? 0);
}

function boostAmount(amount: number, percent: number) {
    return Math.max(0, Math.floor(amount * (1 + percent / 100)));
}

const auraSphereRanks = [
    "Dormant Aura Stone",
    "Awakened Aura Stone",
    "Radiant Aura Stone",
    "Fighting Spirit Aura Stone",
    "Sage Aura Stone",
    "Mythic Aura Stone",
    "Eternal Aura Stone",
];

function auraSphereLevel(character: Pick<Character, "auraSphereLevel">) {
    return Math.max(1, Math.floor(character.auraSphereLevel ?? 1));
}

function auraSphereRankIndex(level: number) {
    return Math.min(auraSphereRanks.length - 1, Math.floor(Math.max(1, level) / 50));
}

function auraSphereRankName(level: number) {
    return auraSphereRanks[auraSphereRankIndex(level)];
}

function auraSphereDustNeeded(level: number) {
    return Math.floor(12 + Math.max(1, level) * 2.5);
}

function getAuraSphereBonuses(character: Pick<Character, "auraSphereLevel">) {
    const level = auraSphereLevel(character);
    return {
        rankName: auraSphereRankName(level),
        regen: level >= 300 ? 5 : level >= 150 ? 2 : level >= 100 ? 2 : level >= 1 ? 1 : 0,
        missionRewardPercent: level >= 100 ? 1 : level >= 50 ? 2 : 0,
        jutsuTrainingSpeedPercent: level >= 250 ? 5 : level >= 150 ? 5 : 0,
        jutsuXpPercent: level >= 250 ? 5 : 0,
        pveDamagePercent: level >= 300 ? 5 : 0,
        avatarAura: level >= 200,
    };
}
function hasEquippedAuraSphere(character: Pick<Character, "equipment">) {
    return character.equipment?.aura === AURA_SPHERE_ITEM_ID || character.equipment?.accessory === AURA_SPHERE_ITEM_ID;
}
function getActiveAuraSphereBonuses(character: Pick<Character, "auraSphereLevel" | "equipment">) {
    if (!hasEquippedAuraSphere(character)) {
        return {
            ...getAuraSphereBonuses(character),
            regen: 0,
            missionRewardPercent: 0,
            jutsuTrainingSpeedPercent: 0,
            jutsuXpPercent: 0,
            pveDamagePercent: 0,
            avatarAura: false,
        };
    }
    return getAuraSphereBonuses(character);
}

export function discountCost(cost: number, percent: number) {
    return Math.max(1, Math.floor(cost * Math.max(0, 1 - percent / 100)));
}

function villageUpgradeCost(key: VillageUpgradeKey, currentLevel: number) {
    const base: Record<VillageUpgradeKey, number> = {
        training: 10,
        jutsuTraining: 12,
        shop: 12,
        townDefense: 14,
        petYard: 12,
        bank: 16,
        missionHall: 14,
        hospital: 12,
    };
    return Math.floor((base[key] ?? 12) + currentLevel * 4 + Math.pow(currentLevel, 1.25) * 2);
}

function getTrainingXpBonus(character: Character) { return villageUpgradeBonus(character, "training") + (character.elderFocus === "training" ? 10 : 0); }
function getJutsuTrainingSpeedBonus(character: Character) { return villageUpgradeBonus(character, "jutsuTraining") + (character.elderFocus === "training" ? 10 : 0); }
function getShopDiscountPercent(character: Character) { return villageUpgradeBonus(character, "shop") + (character.elderFocus === "trade" ? 5 : 0); }
function getTownDefenseGuardBonus(character: Character) { return villageUpgradeBonus(character, "townDefense"); }
function getPetXpBonus(character: Character) { return villageUpgradeBonus(character, "petYard"); }
export function getBankInterestPercent(character: Character) { return villageUpgradeBonus(character, "bank"); }
function getMissionRewardBonus(character: Character) { return villageUpgradeBonus(character, "missionHall"); }
export function getHospitalDiscountPercent(character: Character) { return villageUpgradeBonus(character, "hospital"); }

export function normalizeJutsu(jutsu: Partial<Jutsu> & Pick<Jutsu, "id" | "name" | "type">): Jutsu {
    const tags = normalizeJutsuTags(jutsu.tags);
    const hasMoveTag = tags.some((tag) => tagMatchesName(tag.name, "Move"));
    return {
        id: jutsu.id,
        name: jutsu.name,
        type: jutsu.type,
        element: (jutsu.element != null ? jutsu.element : "Fire") as JutsuElement,
        ap: jutsu.ap ?? 40,
        range: jutsu.range ?? 3,
        effectPower: jutsu.effectPower ?? 50,
        cooldown: jutsu.cooldown ?? 1,
        currentCooldown: jutsu.currentCooldown ?? 0,
        chakraCost: jutsu.chakraCost ?? 20,
        staminaCost: jutsu.staminaCost ?? 10,
        healthCost: jutsu.healthCost ?? 0,
        target: (hasMoveTag ? "EMPTY_GROUND" : (jutsu.target ?? "OPPONENT")) as JutsuTarget,
        method: normalizeJutsuMethod(jutsu.method),
        battleDescription: jutsu.battleDescription ?? `${jutsu.name} strikes %target`,
        healthCostReducePerLvl: jutsu.healthCostReducePerLvl ?? 0,
        chakraCostReducePerLvl: jutsu.chakraCostReducePerLvl ?? 0,
        staminaCostReducePerLvl: jutsu.staminaCostReducePerLvl ?? 0,
        tags,
        description: jutsu.description ?? "",
        image: jutsu.image ?? "",
    };
}

function normalizeCharacter(parsed: Character): Character {
    const level = Math.max(1, Math.min(MAX_LEVEL, Math.floor(parsed.level ?? 1)));
    const xp = level >= MAX_LEVEL ? 0 : Math.max(0, Math.min(xpNeeded(level), Math.floor(parsed.xp ?? 0)));
    const currentMonth = currentMonthKey();
    const expectedMaxHp = maxHpForLevel(level);
    const expectedMaxChakra = maxChakraForLevel(level);
    const expectedMaxStamina = maxStaminaForLevel(level);
    const maxHp = Math.max(parsed.maxHp ?? expectedMaxHp, expectedMaxHp);
    const maxChakra = Math.max(parsed.maxChakra ?? expectedMaxChakra, expectedMaxChakra);
    const maxStamina = Math.max(parsed.maxStamina ?? expectedMaxStamina, expectedMaxStamina);
    const stats = normalizeStats(parsed.stats);

    return {
        ...parsed,
        level,
        xp,
        avatarImage: parsed.avatarImage ?? "",
        specialty: (parsed.specialty ?? "Ninjutsu") as JutsuType,
        storyProgress: parsed.storyProgress ?? 0,
        storyVillage: parsed.storyVillage ?? parsed.village ?? villages[0],
        bankRyo: parsed.bankRyo ?? 0,
        honorSeals: parsed.honorSeals ?? 0,
        auraDust: parsed.auraDust ?? 0,
        auraSphereLevel: Math.max(1, Math.floor(parsed.auraSphereLevel ?? 1)),
        fateShards: parsed.fateShards ?? 0,
        tileCards: parsed.tileCards ?? [],
        savedTileDeck: parsed.savedTileDeck ?? undefined,
        elements: getCharacterElements(parsed),
        hp: Math.min(maxHp, parsed.maxHp && parsed.maxHp < expectedMaxHp ? expectedMaxHp : parsed.hp ?? expectedMaxHp),
        maxHp,
        chakra: Math.min(maxChakra, parsed.maxChakra && parsed.maxChakra < expectedMaxChakra ? expectedMaxChakra : parsed.chakra ?? expectedMaxChakra),
        maxChakra,
        stamina: Math.min(maxStamina, parsed.maxStamina && parsed.maxStamina < expectedMaxStamina ? expectedMaxStamina : parsed.stamina ?? expectedMaxStamina),
        maxStamina,
        rankTitle: parsed.rankTitle ?? rankFromLevel(level),
        storyTitle: parsed.storyTitle ?? "",
        storyTraits: Array.isArray(parsed.storyTraits) ? parsed.storyTraits.filter(Boolean) : [],
        inventory: parsed.inventory ?? [],
        equipment: parsed.equipment ?? {},
        stats,
        unspentStats: Math.max(0, statPointBudgetForProgress(level, xp) - allocatedStatPoints(stats)),
        equippedJutsuIds: (parsed.equippedJutsuIds ?? []).slice(0, 15),
        jutsuMastery: parsed.jutsuMastery ?? [],
        pets: (parsed.pets ?? []).slice(0, 5).map(normalizePet),
        activePetId: parsed.activePetId,
        boneCharms: parsed.boneCharms ?? 0,
        auraStones: parsed.auraStones ?? 0,
        mythicSeals: parsed.mythicSeals ?? 0,
        clan: parsed.clan,
        clanFounder: parsed.clanFounder ?? false,
        clanBattleContrib: parsed.clanBattleContrib ?? 0,
        clanEventContrib: parsed.clanEventContrib ?? 0,
        clanMissionContrib: parsed.clanMissionContrib ?? 0,
        totalStatsTrained: parsed.totalStatsTrained ?? 0,
        totalMissionsCompleted: parsed.totalMissionsCompleted ?? parsed.clanMissionContrib ?? 0,
        totalAiKills: parsed.totalAiKills ?? 0,
        totalPvpKills: parsed.totalPvpKills ?? 0,
        monthlyPvpKills: parsed.pvpKillMonth === currentMonth ? parsed.monthlyPvpKills ?? 0 : 0,
        pvpKillMonth: parsed.pvpKillMonth === currentMonth ? parsed.pvpKillMonth : currentMonth,
        totalVillageRaids: parsed.totalVillageRaids ?? 0,
        villageWarMissionDate: parsed.villageWarMissionDate === currentDateKey() ? parsed.villageWarMissionDate : currentDateKey(),
        villageWarRaidProgress: parsed.villageWarMissionDate === currentDateKey() ? parsed.villageWarRaidProgress ?? 0 : 0,
        villageWarMissionsCompleted: parsed.villageWarMissionDate === currentDateKey() ? parsed.villageWarMissionsCompleted ?? 0 : 0,
        totalTilesExplored: parsed.totalTilesExplored ?? 0,
        totalTournamentsCompleted: parsed.totalTournamentsCompleted ?? 0,
        totalEndlessTowerWins: parsed.totalEndlessTowerWins ?? 0,
        endlessTowerBestWave: parsed.endlessTowerBestWave ?? 0,
        endlessTowerRun: parsed.endlessTowerRun ?? null,
        totalPetWins: parsed.totalPetWins ?? 0,
        defeatedAiIds: Array.isArray(parsed.defeatedAiIds) ? parsed.defeatedAiIds.filter(Boolean) : [],
        rankedRating: parsed.rankedRating ?? 1000,
        rankedWins: parsed.rankedWins ?? 0,
        rankedLosses: parsed.rankedLosses ?? 0,
        weeklyBossKills: parsed.weeklyBossKills ?? {},
        claimedWarCrateIds: Array.isArray(parsed.claimedWarCrateIds) ? parsed.claimedWarCrateIds : [],
        clanContribMonth: parsed.clanContribMonth,
        guardQueued: parsed.guardQueued ?? false,
        hospitalized: parsed.hospitalized ?? false,
        villageUpgrades: normalizeVillageUpgrades(parsed.villageUpgrades),
        lastBankInterestAt: parsed.lastBankInterestAt ?? 0,
        lastDailyReset: currentDateKey(),
        dailyTilesExplored: parsed.lastDailyReset === currentDateKey() ? (parsed.dailyTilesExplored ?? 0) : 0,
        dailyMissionsCompleted: parsed.lastDailyReset === currentDateKey() ? (parsed.dailyMissionsCompleted ?? 0) : 0,
        dailyFateSpins: parsed.lastDailyReset === currentDateKey() ? (parsed.dailyFateSpins ?? 0) : 0,
        dailyAiKills: parsed.lastDailyReset === currentDateKey() ? (parsed.dailyAiKills ?? 0) : 0,
        dailyPetWins: parsed.lastDailyReset === currentDateKey() ? (parsed.dailyPetWins ?? 0) : 0,
        hollowGateRun: parsed.hollowGateRun ?? null,
        hollowGateWardenKills: parsed.hollowGateWardenKills ?? 0,
        hollowGateIntroSeen: parsed.hollowGateIntroSeen ?? false,
        claimedVillageAgendaDate: parsed.claimedVillageAgendaDate,
        claimedMapControlDate: parsed.claimedMapControlDate,
        examsPassed: Array.isArray(parsed.examsPassed) ? parsed.examsPassed.filter(Boolean) : [],
    };
}

function accountKey(name: string) {
    return name.trim().toLowerCase();
}

function loadPlayerAccounts(): PlayerAccounts {
    try {
        const raw = localStorage.getItem(PLAYER_ACCOUNTS_STORAGE);
        return raw ? JSON.parse(raw) : {};
    } catch {
        return {};
    }
}

function savePlayerAccounts(accounts: PlayerAccounts) {
    // Local account cache is only a legacy name list. Server KV is the save/auth source of truth.
    function noImages(_key: string, value: unknown) {
        if (_key === "password") return undefined;
        if (_key === "snapshot") return undefined;
        if (typeof value === "string" && value.startsWith("data:image")) return "";
        return value;
    }
    try {
        localStorage.setItem(PLAYER_ACCOUNTS_STORAGE, JSON.stringify(accounts, noImages));
    } catch {
        // If it still fails for some reason, silently skip — server save is the source of truth
    }
}

function rosterFromAccounts(accounts: PlayerAccounts): PlayerRecord[] {
    return Object.values(accounts).filter((account): account is PlayerAccountSave & { snapshot: NonNullable<PlayerAccountSave["snapshot"]> } => Boolean(account.snapshot)).map((account) => {
        const character = normalizeCharacter(account.snapshot.character);
        return {
            name: character.name,
            level: character.level,
            village: character.village,
            specialty: character.specialty,
            character,
            currentSector: account.snapshot.currentSector ?? 40,
            lastSeenAt: Date.now(),
        };
    });
}

function sameSector(a?: number, b?: number) {
    return Math.floor(Number(a ?? 40)) === Math.floor(Number(b ?? 40));
}

function getOffenseStat(stats: Stats, type: JutsuType | string) {
    if (type === "Any") return Math.max(
        stats.ninjutsuOffense + stats.willpower + stats.speed,
        stats.taijutsuOffense + stats.strength + stats.speed,
        stats.genjutsuOffense + stats.intelligence + stats.willpower,
        stats.bukijutsuOffense + stats.intelligence + stats.strength,
    );
    if (type === "Taijutsu") return stats.taijutsuOffense + stats.strength + stats.speed;
    if (type === "Bukijutsu") return stats.bukijutsuOffense + stats.intelligence + stats.strength;
    if (type === "Genjutsu") return stats.genjutsuOffense + stats.intelligence + stats.willpower;
    return stats.ninjutsuOffense + stats.willpower + stats.speed;
}

function getDefenseStat(stats: Stats, type: JutsuType | string) {
    if (type === "Any") return Math.max(
        stats.ninjutsuDefense + stats.willpower + stats.speed,
        stats.taijutsuDefense + stats.strength + stats.speed,
        stats.genjutsuDefense + stats.intelligence + stats.willpower,
        stats.bukijutsuDefense + stats.intelligence + stats.strength,
    );
    if (type === "Taijutsu") return stats.taijutsuDefense + stats.strength + stats.speed;
    if (type === "Bukijutsu") return stats.bukijutsuDefense + stats.intelligence + stats.strength;
    if (type === "Genjutsu") return stats.genjutsuDefense + stats.intelligence + stats.willpower;
    return stats.ninjutsuDefense + stats.willpower + stats.speed;
}

function clampNumber(value: number, min: number, max: number) {
    return Math.min(max, Math.max(min, value));
}

function diminishingPercent(percent: number, stackIndex: number) {
    const raw = Math.max(0, percent) / 100;
    return raw / (1 + stackIndex * 0.35 + raw * 0.25);
}

function multiplicativeTagMultiplier(tags: { percent?: number }[], direction: "increase" | "decrease") {
    return tags.reduce((multiplier, tag, index) => {
        const effective = diminishingPercent(tag.percent ?? 0, index);
        return direction === "increase"
            ? multiplier * (1 + effective)
            : multiplier / (1 + effective);
    }, 1);
}


function getBloodlineMultiplier(char: Character, allSavedBloodlines: SavedBloodline[]): number {
    if (!char.equippedBloodlineId) return 1.0;
    const adminBl = allSavedBloodlines.find(b => b.id === char.equippedBloodlineId);
    if (adminBl) return adminBl.rank === "S Rank" ? 1.20 : adminBl.rank === "A Rank" ? 1.15 : 1.10;
    const starterBl = starterSavedBloodlines.find(b => b.id === char.equippedBloodlineId);
    if (starterBl) return 1.08;
    return 1.0;
}

function isZeroDamageFortyApJutsu(jutsu: Pick<Jutsu, "id" | "ap">) {
    return jutsu.ap === 40 && jutsu.id !== "basic-attack" && !jutsu.id.startsWith("item-");
}

// Damage buckets:
// 1) base/stat/armor/weather/item outside bonuses, 2) jutsu damage tags, 3) bloodline multiplier.
function calculateDamage(
    jutsu: Jutsu,
    attackerStats: Stats,
    defenderStats: Stats,
    targetMaxHp = HP_CAP,
    bloodlineMult = 1.0,
    armorFactor = 1.0,
    itemMult = 1.0,
    weatherMult = 1.0
) {
    if (isZeroDamageFortyApJutsu(jutsu)) return 0;
    const offense = getOffenseStat(attackerStats, jutsu.type);
    const defense = getDefenseStat(defenderStats, jutsu.type);
    const baselineDamage = targetMaxHp; // EP is now % of target max HP before armor/stat modifiers
    const statFactor = clampNumber(1 + ((offense - defense) / (MAX_STAT * 2)) * 0.85, 0.35, 1.85);
    const effectFactor = Math.max(0, jutsu.effectPower) / 100;
    const bucketOne = baselineDamage * effectFactor * statFactor * armorFactor * itemMult * weatherMult;
    const bucketTwo = bloodlineMult;
    return Math.max(0, Math.floor(bucketOne * bucketTwo));
}

function tagPower(tag: JutsuTag, fallback = 30) {
    return tag.percent > 0 ? tag.percent : fallback;
}

export function jutsuEffectInfo(jutsu: Jutsu, tag: JutsuTag) {
    const pct = tagPower(tag);
    const effectPower = jutsu.effectPower;
    const percentLabel = tag.percent > 0 ? `${tag.percent}%` : "Static";

    if (tag.name === "Damage") return { summary: `Deals damage at ${effectPower}% effect power.`, rule: "Uses the jutsu offense type against the target's matching defense, then applies weather, terrain, bloodline, armor, and status modifiers.", duration: "Instant", value: `${effectPower}% EP` };
    if (tag.name === "Heal") return { summary: `Restores 500 HP to the user.`, rule: "Sets direct damage to 0 and heals the caster for a flat 500 HP.", duration: "Instant", value: "500 HP" };
    if (tag.name === "Shield") return { summary: `Adds 500 shield to the user — always succeeds.`, rule: "Shield absorbs incoming damage before HP. Pierce can bypass shield. Cannot be blocked by Buff Prevent.", duration: "Until broken", value: "500" };
    if (tag.name === "Barrier") return { summary: "Erects an impassable wall tile one step toward the enemy on the battlefield.", rule: "Places a barrier tile that blocks movement for both fighters for 2 rounds. Cannot be bypassed.", duration: "2 rounds", value: "Wall tile" };
    if (tag.name === "Increase Damage Given") return { summary: `Boosts the caster's damage by ${pct}% for 2 rounds.`, rule: "Adds a positive status to the caster that boosts outgoing damage for 2 rounds.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Decrease Damage Given") return { summary: `Makes the target deal ${pct}% less damage.`, rule: "Adds a negative status to the target that lowers outgoing damage.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Increase Damage Taken") return { summary: `Makes the target take ${pct}% more damage.`, rule: "Adds a negative status to the target that raises incoming damage.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Decrease Damage Taken") return { summary: `Makes the user take ${pct}% less damage.`, rule: "Adds a positive status to the caster that lowers incoming damage.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Absorb") return { summary: `Converts ${pct}% of incoming damage into healing.`, rule: "Adds a positive status to the caster. Buff Prevent can block it.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Siphon") return { summary: `Heals the user for ${pct}% of damage dealt.`, rule: "Triggers after damage. Instant heal based on final damage.", duration: "Instant after hit", value: `${pct}%` };
    if (tag.name === "Lifesteal") return { summary: `Applies a 2-round status: your next 2 attacks heal you for ${pct}% of damage dealt.`, rule: "Adds a positive status to the caster. Each attack heals based on final damage.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Reflect") return { summary: `Reflects ${pct}% damage back at attackers.`, rule: "Adds a positive status to the caster. Buff Prevent can block it.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Recoil") return { summary: `Applies ${pct}% recoil to the target.`, rule: "The target suffers capped recoil damage when they attack.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Wound") return { summary: `Makes the target bleed after the hit.`, rule: "Applies a damage-over-time status based on capped post-damage.", duration: "2 rounds", value: `${pct}%` };
    if (tagMatchesName(tag.name, "Ignition")) return { summary: `Applies a 2-round ignition status: next 2 incoming attacks deal an extra ${pct}% damage.`, rule: "Adds a negative status to the enemy. Each time they are attacked while ignited, the attacker's damage is boosted by this percent.", duration: "2 rounds", value: `${pct}%` };
    if (tag.name === "Stun") return { summary: `Removes ${STUN_AP_PENALTY} AP from the target's next turn.`, rule: "Always applies unless Stun Prevent or Debuff Prevent blocks it. It does not skip the target's turn.", duration: "Next turn", value: `-${STUN_AP_PENALTY} AP` };
    if (tag.name === "Bloodline Seal" || tag.name === "Seal") return { summary: "Seals the target's bloodline and suppresses their bloodline damage bonus.", rule: "Always applies unless Debuff Prevent blocks it. While sealed, the target's bloodline multiplier is treated as 1.0 in the combat damage formula.", duration: "2 rounds", value: "No bloodline bonus" };
    if (tag.name === "Elemental Seal") return { summary: "Seals elemental jutsu.", rule: "Always applies unless Debuff Prevent blocks it. Prevents elemental jutsu use while active for 1 round.", duration: "1 round", value: "Always" };
    if (tag.name === "Move") return { summary: "Moves the user on the battlefield.", rule: "Always lets the user choose an open tile within the jutsu range.", duration: "Instant", value: "Always" };
    if (tag.name === "Push") return { summary: "Pushes the target away from the user based on jutsu range.", rule: "Moves the enemy away by the jutsu's range value in tiles.", duration: "Instant", value: "Range tiles" };
    if (tag.name === "Pull") return { summary: "Pulls the target toward the user based on jutsu range.", rule: "Moves the enemy toward the user by the jutsu's range value in tiles.", duration: "Instant", value: "Range tiles" };
    if (tag.name === "Buff Prevent") return { summary: "Blocks positive effects on the target.", rule: "Applies a negative status to the target unless Debuff Prevent blocks it. Prevents new positive effects like Shield, Reflect, Absorb, and similar buffs.", duration: "2 rounds", value: "Always" };
    if (tag.name === "Debuff Prevent") return { summary: "Protects the caster from debuffs for 2 rounds.", rule: "Adds a positive status to the caster. Prevents new debuffs like Stun, Bloodline Seal, Poison, Drain from being applied to them.", duration: "2 rounds", value: "Always" };
    if (tag.name === "Cleanse Prevent") return { summary: "Prevents the target from cleansing debuffs.", rule: "Applies a negative status to the target unless Debuff Prevent blocks it. Cleanse attempts are blocked while active.", duration: "2 rounds", value: "Always" };
    if (tag.name === "Clear Prevent") return { summary: "Prevents clear effects.", rule: "Always stops positive effects from being cleared while active.", duration: "2 rounds", value: "Always" };
    if (tag.name === "Stun Prevent") return { summary: "Prevents stun.", rule: "Always protects against incoming Stun.", duration: "2 rounds", value: "Always" };
    if (tag.name === "Poison") return { summary: `Poisons the target — deals ${pct}% of their max chakra as damage each round.`, rule: "Applies a 2-round negative status that deals damage based on the target's chakra pool.", duration: "2 rounds", value: `${pct}% chakra` };
    if (tag.name === "Drain") return { summary: "Drains the target of 250 HP, chakra, and stamina each round.", rule: "Applies a 2-round negative status that reduces HP, chakra, and stamina simultaneously.", duration: "2 rounds", value: "250/round" };
    if (tag.name === "Pierce") return { summary: "True damage — up to 900, scaled by offense + mastery.", rule: "Ignores armor, shields, damage reduction, damage buffs, and damage debuffs. Pierce jutsus must be 60 AP, and you can equip at most one Pierce jutsu in a loadout. At max stats the cap of 900 is always reached.", duration: "Instant", value: "≤900" };
    if (tag.name === "Copy") return { summary: "Copies enemy positive effects.", rule: "Always copies active positive statuses from the target to the user.", duration: "Up to 2 rounds", value: "Always" };
    if (tag.name === "Mirror") return { summary: "Mirrors negative effects back to the enemy.", rule: "Always transfers the user's non-damage-over-time negative statuses to the target.", duration: "Up to 2 rounds", value: "Always" };
    if (tagMatchesName(tag.name, "Lag")) return { summary: "Increases enemy AP costs.", rule: "Always adds a negative status that makes enemy actions cost more AP for 1 round.", duration: "1 round", value: "Always" };
    if (tagMatchesName(tag.name, "Overclock")) return { summary: "Reduces the user's AP costs.", rule: "Always adds a positive status that makes the user's actions cost less AP.", duration: "2 rounds", value: "Always" };
    if (tag.name === "Increase Heal") return { summary: `Increases healing by ${pct}%.`, rule: "Always adds a positive status that boosts future healing and lifesteal by this amount.", duration: "2 rounds", value: `${pct}%` };
    return { summary: tag.name || "Unnamed effect", rule: "Custom effect tag.", duration: "Varies", value: percentLabel };
}

export function jutsuDisplayAtLevel(jutsu: Jutsu, masteryLevel = JUTSU_MAX_LEVEL): Jutsu {
    const scaled = scaleJutsuByLevel(jutsu, masteryLevel);
    return scaleJutsuTagsForDisplay({ ...jutsu, effectPower: scaled.scaledEffectPower }, masteryLevel);
}

function describeJutsuEffects(jutsu: Jutsu, masteryLevel = JUTSU_MAX_LEVEL) {
    const displayJutsu = jutsuDisplayAtLevel(jutsu, masteryLevel);
    const descriptions = displayJutsu.tags
        .filter((tag) => tag.name)
        .map((tag) => jutsuEffectInfo(displayJutsu, tag).summary);

    return descriptions.length ? descriptions.join(" ") : "No special effects.";
}

function cappedPostDamage(damage: number, percent: number) {
    return Math.floor(Math.min(damage * (percent / 100), damage * 0.6));
}

function jutsuXpNeeded(level: number) {
    if (level >= JUTSU_MAX_LEVEL) return 0;
    return Math.max(1, level) * 50;
}

function getJutsuMastery(character: Character, jutsuId: string): JutsuMastery {
    return character.jutsuMastery?.find((j) => j.jutsuId === jutsuId) ?? { jutsuId, level: 0, xp: 0 };
}

function gainJutsuXp(character: Character, jutsuId: string, amount: number, maxLevelAllowed: number): Character {
    const existing = character.jutsuMastery?.length ? character.jutsuMastery : [];
    const mastery = existing.find((j) => j.jutsuId === jutsuId) ?? { jutsuId, level: 1, xp: 0 };
    let level = mastery.level;
    let xp = mastery.xp + amount;
    while (level < maxLevelAllowed && level < JUTSU_MAX_LEVEL && xp >= jutsuXpNeeded(level)) {
        xp -= jutsuXpNeeded(level);
        level++;
    }
    if (level >= maxLevelAllowed || level >= JUTSU_MAX_LEVEL) {
        level = Math.min(maxLevelAllowed, JUTSU_MAX_LEVEL);
        xp = 0;
    }
    return { ...character, jutsuMastery: [...existing.filter((j) => j.jutsuId !== jutsuId), { jutsuId, level, xp }] };
}

function scaleJutsuByLevel(jutsu: Jutsu, level: number) {
    // EP scales additively: creator value = level 50 max. Each level below 50 subtracts 0.2 EP.
    // Level 1: maxEP - 49×0.2 ˜ maxEP - 9.8. Level 50: maxEP.
    const scaledEffectPower = Math.max(1, Math.floor(jutsu.effectPower - (50 - level) * 0.2));
    const costMultiplier = Math.max(0.8, 1 - Math.max(0, level - 1) * 0.004);
    const chakraCostPercent = jutsu.chakraCost > 0 ? jutsuResourceCostPercent(jutsu, level) : 0;
    const staminaCostPercent = jutsu.staminaCost > 0 ? jutsuResourceCostPercent(jutsu, level) : 0;
    return {
        scaledEffectPower,
        healthCost: Math.max(0, Math.floor((jutsu.healthCost - jutsu.healthCostReducePerLvl * level) * costMultiplier)),
        chakraCost: chakraCostPercent,
        staminaCost: staminaCostPercent,
        chakraCostPercent,
        staminaCostPercent,
    };
}
function jutsuResourceCostPercent(jutsu: Pick<Jutsu, "ap">, masteryLevel = 0) {
    const masteryReduction = masteryLevel >= JUTSU_MAX_LEVEL ? 1 : 0;
    let percent = 0;
    if (jutsu.ap && jutsuResourceCostPercentByAp[jutsu.ap] !== undefined) {
        percent = jutsuResourceCostPercentByAp[jutsu.ap];
    } else if ((jutsu.ap ?? 0) >= 60) {
        percent = 5;
    } else if ((jutsu.ap ?? 0) >= 40) {
        percent = 3;
    } else if ((jutsu.ap ?? 0) > 0) {
        percent = 2;
    }
    return percent > 0 ? Math.max(1, percent - masteryReduction) : 0;
}
function jutsuResourceCost(maxResource: number, jutsu: Pick<Jutsu, "ap" | "chakraCost" | "staminaCost">, resource: "chakra" | "stamina", masteryLevel = 0) {
    const originalCost = resource === "chakra" ? jutsu.chakraCost : jutsu.staminaCost;
    if (!originalCost || originalCost <= 0) return 0;
    return Math.max(1, Math.floor(maxResource * (jutsuResourceCostPercent(jutsu, masteryLevel) / 100)));
}
function formatJutsuResourcePercent(jutsu: Pick<Jutsu, "ap" | "chakraCost" | "staminaCost">, resource: "chakra" | "stamina", masteryLevel = 0) {
    const originalCost = resource === "chakra" ? jutsu.chakraCost : jutsu.staminaCost;
    return originalCost && originalCost > 0 ? `${jutsuResourceCostPercent(jutsu, masteryLevel)}%` : "0%";
}
function jutsuResourceBackingCost(jutsu: Pick<Jutsu, "ap">) {
    return jutsuResourceCostPercent(jutsu) > 0 ? 100 : 0;
}
function lockJutsuResourceCosts<T extends Pick<Jutsu, "ap"> & Partial<Pick<Jutsu, "chakraCost" | "staminaCost" | "chakraCostReducePerLvl" | "staminaCostReducePerLvl">>>(jutsu: T): T {
    const backingCost = jutsuResourceBackingCost(jutsu);
    return {
        ...jutsu,
        chakraCost: backingCost,
        staminaCost: backingCost,
        chakraCostReducePerLvl: 0,
        staminaCostReducePerLvl: 0,
    };
}
function scaleJutsuCostsForCharacter(jutsu: Jutsu, level: number, character: Pick<Character, "maxChakra" | "maxStamina">) {
    const scaled = scaleJutsuByLevel(jutsu, level);
    return {
        ...scaled,
        chakraCost: jutsuResourceCost(character.maxChakra, jutsu, "chakra", level),
        staminaCost: jutsuResourceCost(character.maxStamina, jutsu, "stamina", level),
    };
}
// Returns a copy of the jutsu with tag percents scaled to the given mastery level for display.
// The stored percent is the level-50 max; each level below 50 subtracts 0.2 (same rate as EP).
export function scaleJutsuTagsForDisplay(jutsu: Jutsu, level: number): Jutsu {
    return {
        ...jutsu,
        tags: jutsu.tags.map(tag => ({
            ...tag,
            percent: tag.percent > 0
                ? Math.max(0, Math.floor(effectiveTagPercent(tag, jutsu.bloodlineRank ?? null, level)))
                : 0,
        })),
    };
}

function blankJutsu(index: number, rank: Rank): Jutsu {
    // v4.3: Wound rank caps — S Rank tops at 35%, A/B at 30%.
    const defaultPercent = rank === "S Rank" ? 35 : 30;
    return makeJutsu(makeId(), `Jutsu ${index + 1}`, "Ninjutsu", 60, 4, 40, 7, 300, 300, [
        { name: "", percent: defaultPercent },
        { name: "", percent: defaultPercent },
    ]);
}
function jutsuCountForRank(rank: Rank) { return rank === "B Rank" ? 4 : 5; }
function pointBudgetForRank(rank: Rank) { return rank === "S Rank" ? 11 : rank === "A Rank" ? 10 : 7; }
// v4.3: rank-based Wound percent caps — basic jutsus = 25, A/B bloodline = 30, S bloodline = 35.
function bloodlineTagPercentChoices(rank: Rank) { return rank === "S Rank" ? [30, 35] : [25, 30]; }
function normalizeBloodlineTagPercent(percent: number | undefined, rank: Rank) {
    const choices = bloodlineTagPercentChoices(rank);
    return choices.includes(Number(percent)) ? Number(percent) : choices[choices.length - 1];
}

function tagPointValue(tag: JutsuTag, rank?: Rank | null) {
    if (!tag.name) return 0;
    const tagName = normalizeTagName(tag.name);
    if (cappedDamageTags.includes(tagName)) {
        const cap = tagCapForRank(rank);
        if (tag.percent >= cap) return 0.75; // at-cap bonus cost
        return 0;
    }
    if (percentageTags.includes(tagName)) { // Wound only remains here
        // v4.3: shifted Wound % tiers (new caps are 25 / 30 / 35).
        if (tag.percent >= 35) return 1;
        if (tag.percent >= 30) return 0.5;
        return 0;
    }
    if (["Stun", "Bloodline Seal", "Copy", "Mirror", "Lag", "Overclock", "Debuff Prevent"].includes(tagName)) return 2;
    if (["Reflect", "Buff Prevent", "Cleanse Prevent", "Clear Prevent"].includes(tagName)) return 1.5;
    if (["Shield", "Heal", "Pierce", "Wound", "Barrier", "Drain"].includes(tagName)) return 1;
    if (tagName === "Push") return 1;
    if (tagName === "Pull") return 0.75;
    if (["Move", "Poison", "Ignition"].includes(tagName)) return 0.5;
    return 1;
}

function jutsuPoints(jutsu: Jutsu, rank?: Rank | null) {
    const effectiveRank = rank ?? jutsu.bloodlineRank ?? null;
    let points = jutsu.tags.reduce((sum, tag) => sum + tagPointValue(tag, effectiveRank), 0);
    if (jutsu.ap === 40) points += 1;
    if (jutsu.range >= 5) points += 0.5;
    if (jutsu.target === "EMPTY_GROUND" && (jutsu.method === "AOE_CIRCLE" || jutsu.method === "INSTANT_EFFECT")) points += 1;
    if (!hasFixedEffectPower(jutsu)) {
        if (jutsu.ap === 60 && jutsu.effectPower >= 45) points += 1;
    }
    if (jutsu.cooldown <= 1) points += 0.5;
    return points;
}

function bloodlinePoints(jutsus: Jutsu[]) {
    return jutsus.reduce((sum, jutsu) => sum + jutsuPoints(jutsu), 0);
}

function biomeLabel(biome: Biome) {
    if (biome === "forest") return "Stormveil Coastal Waters";
    if (biome === "snow") return "Frostfang Icefields";
    if (biome === "volcano") return "Ashen Leaf Forest";
    if (biome === "shadow") return "Moonshadow Darklands";
    return "Central Meadow";
}

function getCurrentStory(character: Character) {
    const storyLine = storylines[character.storyVillage || character.village] || storylines["Stormveil Village"];
    return storyLine[character.storyProgress] ?? null;
}

