function allStarterBloodlineJutsus() {
    return starterSavedBloodlines.flatMap((bloodline) => bloodline.jutsus.map((jutsu) => ({ jutsu, rank: bloodline.rank })));
}

function starterBloodlineJutsuRank(jutsuId: string): Rank | undefined {
    return allStarterBloodlineJutsus().find(({ jutsu }) => jutsu.id === jutsuId)?.rank;
}

function getAllJutsus(savedBloodlines: SavedBloodline[], creatorJutsus: Jutsu[], character?: Character | null) {
    const starterBloodlineName = character?.bloodline === "Blue Blade Eyes" ? "Ashen Eyes" : character?.bloodline;
    const starterBloodline = starterSavedBloodlines.find((b) => b.name === starterBloodlineName);
    const equippedBloodline = savedBloodlines.find((b) => b.id === character?.equippedBloodlineId);
    const merged = new Map<string, Jutsu>();
    const markRank = (jutsus: Jutsu[], rank: Rank) => jutsus.map(j => ({ ...j, bloodlineRank: rank }));
    const includeAllStarterBloodlines = !character || isAdminAccountName(character.name);
    [
        ...starterJutsus,
        ...(includeAllStarterBloodlines ? allStarterBloodlineJutsus().map(({ jutsu, rank }) => ({ ...jutsu, bloodlineRank: rank })) : []),
        ...markRank(starterBloodline?.jutsus ?? [], starterBloodline?.rank ?? "B Rank"),
        ...markRank(equippedBloodline?.jutsus ?? [], equippedBloodline?.rank ?? "B Rank"),
        ...creatorJutsus.map((jutsu) => {
            const starterBloodlineRank = starterBloodlineJutsuRank(jutsu.id);
            // Do NOT rebalance here — admin-saved values must be preserved as-is.
            return starterBloodlineRank ? { ...normalizeJutsu(jutsu), bloodlineRank: starterBloodlineRank } : normalizeJutsu(jutsu);
        }),
    ].map(normalizeJutsu).forEach((jutsu) => {
        merged.set(jutsu.id, jutsu);
    });
    return [...merged.values()];
}

function getPvpJutsuLoadout(savedBloodlines: SavedBloodline[], creatorJutsus: Jutsu[], character: Character) {
    return getAllJutsus(savedBloodlines, creatorJutsus, character)
        .filter((jutsu) => character.equippedJutsuIds.includes(jutsu.id));
}

type PlayerCombatSave = {
    character?: Character;
    savedBloodlines?: SavedBloodline[];
    creatorJutsus?: Jutsu[];
    creatorItems?: GameItem[];
};

async function fetchPlayerCombatSave(name: string): Promise<PlayerCombatSave | null> {
    try {
        const res = await fetch(`/api/save/${encodeURIComponent(name.toLowerCase())}`);
        if (!res.ok) return null;
        const data = await res.json() as PlayerCombatSave;
        const saved = Array.isArray(data.savedBloodlines) ? data.savedBloodlines : [];
        const created = Array.isArray(data.creatorJutsus) ? data.creatorJutsus : [];
        const createdItems = Array.isArray(data.creatorItems) ? data.creatorItems : [];
        return {
            character: data.character ? normalizeCharacter(data.character) : undefined,
            savedBloodlines: saved.map((bloodline) => ({
                ...bloodline,
                jutsus: (bloodline.jutsus ?? []).map(normalizeJutsu),
            })),
            // Do NOT rebalance here — admin-saved values must survive combat loading.
            // rebalanceNonBloodlineJutsu must only run on initial creation, never on reads.
            creatorJutsus: created.map(normalizeJutsu),
            creatorItems: createdItems.map(sanitizeArmorAndGloveItem),
        };
    } catch {
        return null;
    }
}

function stringifyPvpSessionPayload(payload: unknown) {
    return JSON.stringify(payload, (_key, value) => typeof value === "string" && value.startsWith("data:image") ? "" : value);
}

function stringifyServerSavePayload(payload: unknown) {
    return JSON.stringify(payload, (_key, value) => typeof value === "string" && value.startsWith("data:image") ? "" : value);
}

async function postPlayerChallengeNotice(targetName: string, challenge: DuelChallenge) {
    for (let attempt = 0; attempt < 3; attempt += 1) {
        try {
            const res = await fetch('/api/player/challenge', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ targetName, challenge }),
            });
            if (res.ok) return true;
        } catch {
            // retry below
        }
        await new Promise(resolve => setTimeout(resolve, 350 + attempt * 500));
    }
    return false;
}

function getJutsuSelectOptions(jutsus: Jutsu[], typeFilter: "All" | JutsuType, elementFilter: "All" | JutsuElement, sortBy: JutsuSort) {
    return [...jutsus]
        .filter((jutsu) => typeFilter === "All" || jutsu.type === typeFilter)
        .filter((jutsu) => elementFilter === "All" || jutsu.element === elementFilter)
        .sort((a, b) => {
            if (sortBy === "ap" || sortBy === "range" || sortBy === "effectPower") return a[sortBy] - b[sortBy];
            if (sortBy === "effect") return describeJutsuEffects(a).localeCompare(describeJutsuEffects(b)) || a.name.localeCompare(b.name);
            return String(a[sortBy]).localeCompare(String(b[sortBy])) || a.name.localeCompare(b.name);
        });
}

function storyToCreatorEvent(step: StoryStep, village: string, index: number): CreatorEvent {
    const slug = village.toLowerCase().replace(/\W+/g, "-");
    const pages = step.pages?.length ? step.pages : [{
        title: step.cinematicTitle,
        scene: step.scene,
        speaker: "Narrator",
        dialogue: step.dialogue,
        choices: [],
    }];
    return {
        id: `story-${slug}-${step.levelReq}-${index}`,
        name: `${village}: ${step.title}`,
        biome: step.biome ?? villageBiomeMap[village] ?? "central",
        icon: step.bossIcon,
        eventKind: "visualNovel",
        trigger: "manual",
        vnTitle: step.title,
        vnScene: step.scene,
        vnSpeaker: pages[0]?.speaker ?? "Narrator",
        image: "",
        aiProfileId: step.aiProfileId,
        village,
        kageFinale: step.kageFinale,
        liberatorTitle: step.liberatorTitle,
        vnPages: pages,
        levelReq: step.levelReq,
        xpReward: step.rewardXp,
        ryoReward: step.rewardRyo,
        staminaReward: 0,
        dialogue: step.dialogue,
    };
}

function blankAiRule(): AiRule {
    return { id: makeId(), condition: "always", value: 1, action: "use_highest_power_jutsu" };
}

